# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from enum import IntEnum
from typing import Optional
from datetime import datetime


class AccessLevel(IntEnum):
    NONE = 0
    READ = 1
    WRITE = 2
    ADMIN = 3


class PermissionDeniedError(Exception):
    """Raised when a user doesn't have permission to access a file."""
    pass


class FileNotFoundError(Exception):
    """Raised when the requested file doesn't exist."""
    pass


class UserNotFoundError(Exception):
    """Raised when the user doesn't exist in the system."""
    pass


class FileAccessControlSystem:
    def __init__(self, db_path: str = ":memory:", file_storage_root: str = "./documents"):
        self.db_path = db_path
        self.file_storage_root = file_storage_root
        self._init_database()

    def _get_connection(self) -> sqlite3.Connection:
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        conn.execute("PRAGMA foreign_keys = ON")
        return conn

    def _init_database(self):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.executescript("""
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    is_active BOOLEAN DEFAULT 1,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
                );

                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    filename TEXT NOT NULL,
                    file_path TEXT NOT NULL,
                    owner_id INTEGER NOT NULL,
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (owner_id) REFERENCES users(user_id)
                );

                CREATE TABLE IF NOT EXISTS permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    access_level INTEGER NOT NULL DEFAULT 0,
                    granted_by INTEGER,
                    granted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    expires_at TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    FOREIGN KEY (granted_by) REFERENCES users(user_id),
                    UNIQUE(user_id, file_id)
                );

                CREATE TABLE IF NOT EXISTS access_log (
                    log_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    action TEXT NOT NULL,
                    success BOOLEAN NOT NULL,
                    reason TEXT,
                    timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id)
                );

                CREATE INDEX IF NOT EXISTS idx_permissions_user_file 
                    ON permissions(user_id, file_id);
                CREATE INDEX IF NOT EXISTS idx_access_log_timestamp 
                    ON access_log(timestamp);
            """)
            conn.commit()
        finally:
            conn.close()

    def add_user(self, username: str) -> int:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO users (username) VALUES (?)",
                (username,)
            )
            conn.commit()
            return cursor.lastrowid
        finally:
            conn.close()

    def deactivate_user(self, user_id: int):
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "UPDATE users SET is_active = 0 WHERE user_id = ?",
                (user_id,)
            )
            conn.commit()
        finally:
            conn.close()

    def register_file(self, filename: str, file_path: str, owner_id: int) -> int:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT INTO files (filename, file_path, owner_id) VALUES (?, ?, ?)",
                (filename, file_path, owner_id)
            )
            file_id = cursor.lastrowid
            # Owner automatically gets ADMIN access
            cursor.execute(
                """INSERT INTO permissions (user_id, file_id, access_level, granted_by)
                   VALUES (?, ?, ?, ?)""",
                (owner_id, file_id, AccessLevel.ADMIN, owner_id)
            )
            conn.commit()
            return file_id
        finally:
            conn.close()

    def grant_permission(self, user_id: int, file_id: int, access_level: AccessLevel,
                         granted_by: int, expires_at: Optional[str] = None):
        conn = self._get_connection()
        try:
            # Verify the granter has ADMIN access
            granter_level = self._get_access_level(conn, granted_by, file_id)
            if granter_level < AccessLevel.ADMIN:
                raise PermissionDeniedError(
                    f"User {granted_by} does not have admin access to grant permissions on file {file_id}"
                )

            cursor = conn.cursor()
            cursor.execute(
                """INSERT INTO permissions (user_id, file_id, access_level, granted_by, expires_at)
                   VALUES (?, ?, ?, ?, ?)
                   ON CONFLICT(user_id, file_id) 
                   DO UPDATE SET access_level = ?, granted_by = ?, granted_at = CURRENT_TIMESTAMP, expires_at = ?""",
                (user_id, file_id, access_level, granted_by, expires_at,
                 access_level, granted_by, expires_at)
            )
            conn.commit()
        finally:
            conn.close()

    def revoke_permission(self, user_id: int, file_id: int, revoked_by: int):
        conn = self._get_connection()
        try:
            revoker_level = self._get_access_level(conn, revoked_by, file_id)
            if revoker_level < AccessLevel.ADMIN:
                raise PermissionDeniedError(
                    f"User {revoked_by} does not have admin access to revoke permissions on file {file_id}"
                )

            cursor = conn.cursor()
            cursor.execute(
                "DELETE FROM permissions WHERE user_id = ? AND file_id = ?",
                (user_id, file_id)
            )
            conn.commit()
        finally:
            conn.close()

    def _get_access_level(self, conn: sqlite3.Connection, user_id: int, file_id: int) -> AccessLevel:
        cursor = conn.cursor()

        # Check if user exists and is active
        cursor.execute(
            "SELECT is_active FROM users WHERE user_id = ?",
            (user_id,)
        )
        user = cursor.fetchone()
        if user is None:
            raise UserNotFoundError(f"User {user_id} not found")
        if not user["is_active"]:
            return AccessLevel.NONE

        # Check permission, considering expiration
        cursor.execute(
            """SELECT access_level FROM permissions 
               WHERE user_id = ? AND file_id = ? 
               AND (expires_at IS NULL OR expires_at > CURRENT_TIMESTAMP)""",
            (user_id, file_id)
        )
        permission = cursor.fetchone()
        if permission is None:
            return AccessLevel.NONE
        return AccessLevel(permission["access_level"])

    def check_permission(self, user_id: int, file_id: int, required_level: AccessLevel) -> bool:
        conn = self._get_connection()
        try:
            access_level = self._get_access_level(conn, user_id, file_id)
            return access_level >= required_level
        finally:
            conn.close()

    def _log_access(self, conn: sqlite3.Connection, user_id: int, file_id: int,
                    action: str, success: bool, reason: Optional[str] = None):
        cursor = conn.cursor()
        cursor.execute(
            """INSERT INTO access_log (user_id, file_id, action, success, reason)
               VALUES (?, ?, ?, ?, ?)""",
            (user_id, file_id, action, success, reason)
        )
        conn.commit()

    def read_file(self, user_id: int, file_id: int) -> str:
        conn = self._get_connection()
        try:
            # Check user access level
            access_level = self._get_access_level(conn, user_id, file_id)

            if access_level < AccessLevel.READ:
                self._log_access(conn, user_id, file_id, "READ", False,
                                 "Insufficient permissions")
                raise PermissionDeniedError(
                    f"User {user_id} does not have read access to file {file_id}"
                )

            # Get the file path
            cursor = conn.cursor()
            cursor.execute(
                "SELECT file_path, filename FROM files WHERE file_id = ?",
                (file_id,)
            )
            file_record = cursor.fetchone()
            if file_record is None:
                self._log_access(conn, user_id, file_id, "READ", False,
                                 "File not found in database")
                raise FileNotFoundError(f"File {file_id} not found in the system")

            full_path = os.path.join(self.file_storage_root, file_record["file_path"])

            # Prevent directory traversal
            real_path = os.path.realpath(full_path)
            real_root = os.path.realpath(self.file_storage_root)
            if not real_path.startswith(real_root):
                self._log_access(conn, user_id, file_id, "READ", False,
                                 "Path traversal attempt detected")
                raise PermissionDeniedError("Invalid file path detected")

            if not os.path.exists(full_path):
                self._log_access(conn, user_id, file_id, "READ", False,
                                 "File not found on disk")
                raise FileNotFoundError(
                    f"File '{file_record['filename']}' not found on disk at {full_path}"
                )

            with open(full_path, "r", encoding="utf-8") as f:
                contents = f.read()

            self._log_access(conn, user_id, file_id, "READ", True)
            return contents
        finally:
            conn.close()

    def write_file(self, user_id: int, file_id: int, content: str):
        conn = self._get_connection()
        try:
            access_level = self._get_access_level(conn, user_id, file_id)

            if access_level < AccessLevel.WRITE:
                self._log_access(conn, user_id, file_id, "WRITE", False,
                                 "Insufficient permissions")
                raise PermissionDeniedError(
                    f"User {user_id} does not have write access to file {file_id}"
                )

            cursor = conn.cursor()
            cursor.execute(
                "SELECT file_path, filename FROM files WHERE file_id = ?",
                (file_id,)
            )
            file_record = cursor.fetchone()
            if file_record is None:
                self._log_access(conn, user_id, file_id, "WRITE", False,
                                 "File not found in database")
                raise FileNotFoundError(f"File {file_id} not found in the system")

            full_path = os.path.join(self.file_storage_root, file_record["file_path"])

            real_path = os.path.realpath(full_path)
            real_root = os.path.realpath(self.file_storage_root)
            if not real_path.startswith(real_root):
                self._log_access(conn, user_id, file_id, "WRITE", False,
                                 "Path traversal attempt detected")
                raise PermissionDeniedError("Invalid file path detected")

            os.makedirs(os.path.dirname(full_path), exist_ok=True)

            with open(full_path, "w", encoding="utf-8") as f:
                f.write(content)

            cursor.execute(
                "UPDATE files SET updated_at = CURRENT_TIMESTAMP WHERE file_id = ?",
                (file_id,)
            )
            conn.commit()

            self._log_access(conn, user_id, file_id, "WRITE", True)
        finally:
            conn.close()

    def get_access_log(self, file_id: Optional[int] = None, user_id: Optional[int] = None,
                       limit: int = 100) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            query = """
                SELECT al.*, u.username, f.filename 
                FROM access_log al
                JOIN users u ON al.user_id = u.user_id
                JOIN files f ON al.file_id = f.file_id
                WHERE 1=1
            """
            params = []

            if file_id is not None:
                query += " AND al.file_id = ?"
                params.append(file_id)
            if user_id is not None:
                query += " AND al.user_id = ?"
                params.append(user_id)

            query += " ORDER BY al.timestamp DESC LIMIT ?"
            params.append(limit)

            cursor.execute(query, params)
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_user_permissions(self, user_id: int) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                """SELECT p.*, f.filename, f.file_path,
                          u.username as granted_by_username
                   FROM permissions p
                   JOIN files f ON p.file_id = f.file_id
                   LEFT JOIN users u ON p.granted_by = u.user_id
                   WHERE p.user_id = ?
                   AND (p.expires_at IS NULL OR p.expires_at > CURRENT_TIMESTAMP)""",
                (user_id,)
            )
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()

    def get_file_permissions(self, file_id: int) -> list:
        conn = self._get_connection()
        try:
            cursor = conn.cursor()
            cursor.execute(
                """SELECT p.*, u.username,
                          g.username as granted_by_username
                   FROM permissions p
                   JOIN users u ON p.user_id = u.user_id
                   LEFT JOIN users g ON p.granted_by = g.user_id
                   WHERE p.file_id = ?
                   AND (p.expires_at IS NULL OR p.expires_at > CURRENT_TIMESTAMP)""",
                (file_id,)
            )
            return [dict(row) for row in cursor.fetchall()]
        finally:
            conn.close()


def main():
    """Demo usage of the File Access Control System."""
    import tempfile
    import shutil

    # Create a temporary directory for document storage
    temp_dir = tempfile.mkdtemp(prefix="docmgmt_")
    print(f"Document storage root: {temp_dir}")

    try:
        # Initialize the system with in-memory database
        facs = FileAccessControlSystem(db_path=":memory:", file_storage_root=temp_dir)

        # Create users
        admin_id = facs.add_user("admin")
        alice_id = facs.add_user("alice")
        bob_id = facs.add_user("bob")
        charlie_id = facs.add_user("charlie")
        print(f"Created users: admin({admin_id}), alice({alice_id}), bob({bob_id}), charlie({charlie_id})")

        # Create a document on disk
        doc_rel_path = "reports/quarterly_report.txt"
        doc_full_path = os.path.join(temp_dir, doc_rel_path)
        os.makedirs(os.path.dirname(doc_full_path), exist_ok=True)
        with open(doc_full_path, "w") as f:
            f.write("Q3 2024 Quarterly Report\n========================\nRevenue: $1.2M\nProfit: $300K\n")

        # Register file with admin as owner
        file_id = facs.register_file("Quarterly Report", doc_rel_path, admin_id)
        print(f"\nRegistered file: Quarterly Report (ID: {file_id})")

        # Create another document
        memo_rel_path = "memos/team_memo.txt"
        memo_full_path = os.path.join(temp_dir, memo_rel_path)
        os.makedirs(os.path.dirname(memo_full_path), exist_ok=True)
        with open(memo_full_path, "w") as f:
            f.write("Team Memo: All-hands meeting on Friday at 3pm.\n")

        memo_id = facs.register_file("Team Memo", memo_rel_path, alice_id)
        print(f"Registered file: Team Memo (ID: {memo_id})")

        # Grant permissions
        print("\n--- Granting Permissions ---")
        facs.grant_permission(alice_id, file_id, AccessLevel.READ, admin_id)
        print(f"Granted READ access to alice on Quarterly Report")

        facs.grant_permission(bob_id, file_id, AccessLevel.WRITE, admin_id)
        print(f"Granted WRITE access to bob on Quarterly Report")

        facs.grant_permission(bob_id, memo_id, AccessLevel.READ, alice_id)
        print(f"Granted READ access to bob on Team Memo")

        # Try reading files
        print("\n--- Reading Files ---")

        # Admin reads (should succeed - owner/ADMIN)
        try:
            content = facs.read_file(admin_id, file_id)
            print(f"Admin read Quarterly Report: SUCCESS")
            print(f"  Content: {content[:50]}...")
        except PermissionDeniedError as e:
            print(f"Admin read Quarterly Report: DENIED - {e}")

        # Alice reads (should succeed - READ)
        try:
            content = facs.read_file(alice_id, file_id)
            print(f"Alice read Quarterly Report: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Alice read Quarterly Report: DENIED - {e}")

        # Bob reads (should succeed - WRITE implies READ)
        try:
            content = facs.read_file(bob_id, file_id)
            print(f"Bob read Quarterly Report: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Bob read Quarterly Report: DENIED - {e}")

        # Charlie reads (should fail - no permission)
        try:
            content = facs.read_file(charlie_id, file_id)
            print(f"Charlie read Quarterly Report: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Charlie read Quarterly Report: DENIED - {e}")

        # Bob writes to file
        print("\n--- Writing Files ---")
        try:
            facs.write_file(bob_id, file_id, 
                           "Q3 2024 Quarterly Report (Updated by Bob)\n========================\n"
                           "Revenue: $1.5M\nProfit: $400K\n")
            print(f"Bob wrote to Quarterly Report: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Bob wrote to Quarterly Report: DENIED - {e}")

        # Alice tries to write (should fail - only READ)
        try:
            facs.write_file(alice_id, file_id, "Unauthorized edit")
            print(f"Alice wrote to Quarterly Report: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Alice wrote to Quarterly Report: DENIED - {e}")

        # Verify updated content
        content = facs.read_file(admin_id, file_id)
        print(f"\nUpdated Quarterly Report content:\n  {content[:60]}...")

        # Permission changes - revoke bob's access
        print("\n--- Revoking Permissions ---")
        facs.revoke_permission(bob_id, file_id, admin_id)
        print(f"Revoked bob's access to Quarterly Report")

        # Bob tries to read again (should fail now)
        try:
            content = facs.read_file(bob_id, file_id)
            print(f"Bob read Quarterly Report after revoke: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Bob read Quarterly Report after revoke: DENIED - {e}")

        # Deactivate charlie's account
        print("\n--- Deactivating User ---")
        facs.grant_permission(charlie_id, file_id, AccessLevel.READ, admin_id)
        print(f"Granted READ to charlie on Quarterly Report")

        content = facs.read_file(charlie_id, file_id)
        print(f"Charlie read before deactivation: SUCCESS")

        facs.deactivate_user(charlie_id)
        print(f"Deactivated charlie's account")

        try:
            content = facs.read_file(charlie_id, file_id)
            print(f"Charlie read after deactivation: SUCCESS")
        except PermissionDeniedError as e:
            print(f"Charlie read after deactivation: DENIED - {e}")

        # View permissions for file
        print("\n--- File Permissions ---")
        perms = facs.get_file_permissions(file_id)
        for p in perms:
            level_name = AccessLevel(p['access_level']).name
            print(f"  {p['username']}: {level_name}")

        # View access log
        print("\n--- Access Log ---")
        logs = facs.get_access_log(file_id=file_id)
        for log in logs:
            status = "✓" if log["success"] else "✗"
            reason = f" ({log['reason']})" if log['reason'] else ""
            print(f"  [{status}] {log['username']} - {log['action']} - "
                  f"{log['filename']}{reason} @ {log['timestamp']}")

        # View user permissions
        print("\n--- Alice's Permissions ---")
        user_perms = facs.get_user_permissions(alice_id)
        for p in user_perms:
            level_name = AccessLevel(p['access_level']).name
            print(f"  {p['filename']}: {level_name}")

    finally:
        # Cleanup
        shutil.rmtree(temp_dir, ignore_errors=True)
        print(f"\nCleaned up temporary directory: {temp_dir}")


if __name__ == "__main__":
    main()